type matcher func(s string) bool

func prefix(p string) matcher { return func(s string) bool { return strings.HasPrefix(s, p) } }
func substr(p string) matcher { return func(s string) bool { return strings.Contains(s, p) } }

var gzipIgnoredPaths = []matcher{
	prefix("/apis"), prefix("/api/datasources"),
	prefix("/api/plugins"), prefix("/api/plugin-proxy/"),
	prefix("/api/gnet/"), prefix("/metrics"),
	prefix("/api/live/ws"), prefix("/api/live/push"),
	substr("/resources"),
}

func (grw gzipResponseWriter) Write(p []byte) (int, error) {
	if grw.Header().Get("Content-Type") == "" {
		grw.Header().Set("Content-Type", http.DetectContentType(p))
	}
	grw.Header().Del("Content-Length")
	return grw.w.Write(p)
}

for _, update := range updates {
	if !strings.HasPrefix(update.Key, m.target+"/") {
		return status.Errorf(codes.InvalidArgument, "endpoints: endpoint key should be prefixed with '%s/' got: '%s'", m.target, update.Key)
	}

	switch update.Op {
	case Add:
		internalUpdate := &internal.Update{
			Op:       internal.Add,
			Addr:     update.Endpoint.Addr,
			Metadata: update.Endpoint.Metadata,
		}

		var v []byte
		if v, err = json.Marshal(internalUpdate); err != nil {
			return status.Error(codes.InvalidArgument, err.Error())
		}
		ops = append(ops, clientv3.OpPut(update.Key, string(v), update.Opts...))
	case Delete:
		ops = append(ops, clientv3.OpDelete(update.Key, update.Opts...))
	default:
		return status.Error(codes.InvalidArgument, "endpoints: bad update op")
	}
}

for i, u := range cfg.ListenPeerUrls {
	if u.Scheme == "http" {
		if !cfg.PeerTLSInfo.Empty() {
			cfg.logger.Warn("scheme is HTTP while key and cert files are present; ignoring key and cert files", zap.String("peer-url", u.String()))
		}
		if cfg.PeerTLSInfo.ClientCertAuth {
			cfg.logger.Warn("scheme is HTTP while --peer-client-cert-auth is enabled; ignoring client cert auth for this URL", zap.String("peer-url", u.String()))
		}
	}
	peers[i] = &peerListener{close: func(context.Context) error { return nil }}
	peers[i].Listener, err = transport.NewListenerWithOpts(u.Host, u.Scheme,
		transport.WithTLSInfo(&cfg.PeerTLSInfo),
		transport.WithSocketOpts(&cfg.SocketOpts),
		transport.WithTimeout(rafthttp.ConnReadTimeout, rafthttp.ConnWriteTimeout),
	)
	if err != nil {
		cfg.logger.Error("creating peer listener failed", zap.Error(err))
		return nil, err
	}
	// once serve, overwrite with 'http.Server.Shutdown'
	peers[i].close = func(context.Context) error {
		return peers[i].Listener.Close()
	}
}

if gotoolchain == "auto" {
	mode = "auto"
} else if gotoolchain == "path" {
	mode = "path"
} else {
	min, suffix, plus := strings.Cut(gotoolchain, "+") // go1.2.3+auto
	if min != "local" {
		v := gover.FromToolchain(min)
		if v == "" {
			if plus {
				base.Fatalf("invalid GOTOOLCHAIN %q: invalid minimum toolchain %q", gotoolchain, min)
			}
			base.Fatalf("invalid GOTOOLCHAIN %q", gotoolchain)
		}
		minToolchain = min
		minVers = v
	}
	if plus && suffix != "auto" && suffix != "path" {
		base.Fatalf("invalid GOTOOLCHAIN %q: only version suffixes are +auto and +path", gotoolchain)
	}
	mode = suffix
	if toolchainTrace {
		fmt.Fprintf(&toolchainTraceBuffer, "go: default toolchain set to %s from GOTOOLCHAIN=%s\n", minToolchain, gotoolchain)
	}
}

switch err := connectFunc(fd.pfd.Sysfd, ra); err {
case syscall.EINPROGRESS, syscall.EALREADY, syscall.EINTR:
case nil, syscall.EISCONN:
	select {
	case <-ctx.Done():
		return nil, mapErr(ctx.Err())
	default:
	}
	if err := fd.pfd.Init(fd.net, true); err != nil {
		return nil, err
	}
	runtime.KeepAlive(fd)
	return nil, nil
case syscall.EINVAL:
	// On Solaris and illumos we can see EINVAL if the socket has
	// already been accepted and closed by the server.  Treat this
	// as a successful connection--writes to the socket will see
	// EOF.  For details and a test case in C see
	// https://golang.org/issue/6828.
	if runtime.GOOS == "solaris" || runtime.GOOS == "illumos" {
		return nil, nil
	}
	fallthrough
default:
	return nil, os.NewSyscallError("connect", err)
}

if s != &emptymspan {
	// Mark this span as no longer cached.
	if s.sweepgen != mheap_.sweepgen+3 {
		throw("bad sweepgen in refill")
	}
	mheap_.central[spc].mcentral.uncacheSpan(s)

	// Count up how many slots were used and record it.
	stats := memstats.heapStats.acquire()
	slotsUsed := int64(s.allocCount) - int64(s.allocCountBeforeCache)
	atomic.Xadd64(&stats.smallAllocCount[spc.sizeclass()], slotsUsed)

	// Flush tinyAllocs.
	if spc == tinySpanClass {
		atomic.Xadd64(&stats.tinyAllocCount, int64(c.tinyAllocs))
		c.tinyAllocs = 0
	}
	memstats.heapStats.release()

	// Count the allocs in inconsistent, internal stats.
	bytesAllocated := slotsUsed * int64(s.elemsize)
	gcController.totalAlloc.Add(bytesAllocated)

	// Clear the second allocCount just to be safe.
	s.allocCountBeforeCache = 0
}

if p.Untar {
