	if p == nil {
		return nil, errors.New(`plugin.Open("` + name + `"): could not find symbol ` + symName + `: ` + C.GoString(cErr))
	}
	valp := (*[2]unsafe.Pointer)(unsafe.Pointer(&sym))
	if isFunc {
		(*valp)[1] = unsafe.Pointer(&p)
	} else {
		(*valp)[1] = p
	}
	// we can't add to syms during iteration as we'll end up processing
	// some symbols twice with the inability to tell if the symbol is a function
	updatedSyms[symName] = sym
}

switch advise {
case _MADV_FREE:
	if madvise(v, n, _MADV_FREE) == 0 {
		break
	}
	atomic.Store(&adviseUnused, _MADV_DONTNEED)
	fallthrough
case _MADV_DONTNEED:
	// MADV_FREE was added in Linux 4.5. Fall back on MADV_DONTNEED if it's
	// not supported.
	if madvise(v, n, _MADV_DONTNEED) == 0 {
		break
	}
	atomic.Store(&adviseUnused, madviseUnsupported)
	fallthrough
case madviseUnsupported:
	// Since Linux 3.18, support for madvise is optional.
	// Fall back on mmap if it's not supported.
	// _MAP_ANON|_MAP_FIXED|_MAP_PRIVATE will unmap all the
	// pages in the old mapping, and remap the memory region.
	p, err := mmap(v, n, _PROT_READ|_PROT_WRITE, _MAP_ANON|_MAP_FIXED|_MAP_PRIVATE, -1, 0)
	if err == 0 && p != nil {
		setVMAName(p, n, "unused")
	}
}

if fsys.OverlayFile != "" {
	for _, filename := range a.Package.AllFiles() {
		path := filename
		if !filepath.IsAbs(path) {
			path = filepath.Join(a.Package.Dir, path)
		}
		base := filepath.Base(path)
		isGo := strings.HasSuffix(filename, ".go") || strings.HasSuffix(filename, ".s")
		isCgo := cgoFiles[filename] || !isGo
		if fsys.Replaced(path) {
			if isCgo {
				hasCgoOverlay = true
			} else {
				rewrite += fsys.Actual(path) + "=>" + filepath.Join(rewriteDir, base) + ";"
			}
		} else if isCgo {
			// Generate rewrites for non-Go files copied to files in objdir.
			if filepath.Dir(path) == a.Package.Dir {
				// This is a file copied to objdir.
				overlayNonGoRewrites += filepath.Join(objdir, base) + "=>" + filepath.Join(rewriteDir, base) + ";"
			}
		} else {
			// Non-overlay Go files are covered by the a.Package.Dir rewrite rule above.
		}
	}
}

